#include <stdio.h>
#include <stdbool.h>

#define TLB_SIZE 4
#define PAGE_TABLE_SIZE 16

typedef struct {
    int virtual_page;
    int frame_number;
    bool valid;
} TLBEntry;

TLBEntry tlb[TLB_SIZE];
int tlb_index = 0;
int page_table[PAGE_TABLE_SIZE] = {0, 1, 2, 3, -1, 5, -1, 7, 8, 9, -1, 11, -1, 13, 14, 15};

// Initialize TLB
void init_tlb() {
    for (int i = 0; i < TLB_SIZE; i++) {
        tlb[i].valid = false;
    }
}

// Search TLB for virtual page
int tlb_lookup(int vpn) {
    for (int i = 0; i < TLB_SIZE; i++) {
        if (tlb[i].valid && tlb[i].virtual_page == vpn) {
            return tlb[i].frame_number;  // TLB Hit
        }
    }
    return -1;  // TLB Miss
}

// Add entry to TLB (FIFO replacement)
void tlb_insert(int vpn, int frame) {
    tlb[tlb_index].virtual_page = vpn;
    tlb[tlb_index].frame_number = frame;
    tlb[tlb_index].valid = true;
    tlb_index = (tlb_index + 1) % TLB_SIZE;
}

// Translate virtual to physical address
int translate_address(int virtual_addr, bool *tlb_hit) {
    int vpn = virtual_addr / 256;  // Assuming page size 256
    int offset = virtual_addr % 256;

    int frame = tlb_lookup(vpn);

    if (frame != -1) {
        *tlb_hit = true;
    } else {
        *tlb_hit = false;
        frame = page_table[vpn];
        if (frame != -1) {
            tlb_insert(vpn, frame);
        }
    }

    return (frame * 256) + offset;
}

int main() {
    init_tlb();
    bool hit;
    int phys_addr = translate_address(1024, &hit);  // VPN=4
    printf("Virtual: 1024 -> Physical: %d, TLB Hit: %s\n", phys_addr, hit ? "Yes" : "No");
    return 0;
}
